/// <summary>
/// Purchase agreement import
/// </summary>
public class ETG_Acu_PurchAgreementHeaderImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_PurchAgreementHeaderImport  purchAgreementHeaderimport;

    purchAgreementHeaderimport = ETG_Acu_PurchAgreementHeaderImport::construct();

    if (purchAgreementHeaderimport.prompt())
    {
        purchAgreementHeaderimport.runOperation();
    }
}

public static ETG_Acu_PurchAgreementHeaderImport construct()
{
    return new ETG_Acu_PurchAgreementHeaderImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    PurchPurchaseAgreementHeaderV2Entity    purchAgreementHeader;

    VendTable                               vendTable;
    DirPartyBaseEntity                      vendTableDirParty;
    DictEnum                                dictEnumCommitmentType = new DictEnum(enumNum(CommitmentType));

    select firstonly vendTable
        exists join vendTableDirParty
            where vendTableDirParty.PartyRecordId ==  vendTable.Party
                && vendTableDirParty.OrganizationNumber == conpeek(_con, 4);

    purchAgreementHeader.PURCHASEAGREEMENTID                    = conpeek(_con, 1);
    purchAgreementHeader.AGREEMENTSTATUS                        = AgreementState::Effective;
    purchAgreementHeader.AgreementType                          = conpeek(_con, 3);
    purchAgreementHeader.AgreementVendorAccountNumber           = vendTable.AccountNum;
    purchAgreementHeader.AgreementWorkflowStatus                = PurchAgreementWorkflowStatus::NotSubmitted;
    purchAgreementHeader.BuyerAccountNum                        = conpeek(_con, 6);
    purchAgreementHeader.BuyerBank                              = conpeek(_con, 7);
    purchAgreementHeader.BuyingLegalEntityId                    = conpeek(_con, 8);
    purchAgreementHeader.Consignee                              = conpeek(_con, 9);
    purchAgreementHeader.CurrencyCode                           = conpeek(_con, 10);
    purchAgreementHeader.DefaultCommitmentType                  = dictEnumCommitmentType.symbol2Value(conpeek(_con, 11));
    purchAgreementHeader.DefaultEffectiveDate                   = str2Date(conpeek(_con, 12), 123);
    purchAgreementHeader.DefaultExpirationDate                  = str2Date(conpeek(_con, 13), 123);
    purchAgreementHeader.DeliveryModeCode                       = conpeek(_con, 14);
    purchAgreementHeader.DeliveryTermsCode                      = conpeek(_con, 15);
    purchAgreementHeader.DocumentTitle                          = conpeek(_con, 16);
    purchAgreementHeader.ExternalDocumentReference              = conpeek(_con, 17);
    purchAgreementHeader.Notifytodifferentparty                 = conpeek(_con, 18);
    purchAgreementHeader.PaymentTermsName                       = conpeek(_con, 19);
    purchAgreementHeader.PortOfDischarge                        = conpeek(_con, 20);
    purchAgreementHeader.PortOfDischargeDesc                    = conpeek(_con, 21);
    purchAgreementHeader.PortOfLoading                          = conpeek(_con, 22);
    purchAgreementHeader.PortOfLoadingDesc                      = conpeek(_con, 23);
    purchAgreementHeader.PurchaseAgreementClassificationName    = conpeek(_con, 24);
    purchAgreementHeader.PurchaseOrderPoolId                    = conpeek(_con, 25);

    if (conpeek(_con, 26))
    {
        select firstonly vendTable
            exists join vendTableDirParty
                where vendTableDirParty.PartyRecordId ==  vendTable.Party
                    && vendTableDirParty.OrganizationNumber == conpeek(_con, 26);

        purchAgreementHeader.SellerAccountNum                   = vendTable.AccountNum;
    }

    purchAgreementHeader.SellerBank                             = conpeek(_con, 27);
    purchAgreementHeader.Through                                = conpeek(_con, 28);

    // BusinessUnit (29)	Contract (30)	Department (31)	Intercompany (32)	Plant_Warehouse_Office (33)	Product_Service (34)	Trader_Employee (35)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    purchAgreementHeader.DefaultLedgerDimensionDisplayValue     = conPeek(_con, 33) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 31) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 35) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 34) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 29) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 32) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 30);


    purchAgreementHeader.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = 'Import purchase agreement header';

    return ret;
}
